import java.util.*;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        long totalSub = (long) n * (n + 1) / 2;
        if (k > totalSub) {
            return -1;
        }

        long invalid = totalSub;
        TreeSet<Integer> marked = new TreeSet<>();

        for (int t = 0; t < n; t++) {
            int pos = (int) order[t];
            Integer leftMarked = marked.lower(pos);
            Integer rightMarked = marked.higher(pos);

            int L = (leftMarked == null) ? 0 : leftMarked + 1;
            int R = (rightMarked == null) ? n - 1 : rightMarked - 1;

            long segmentLen = R - L + 1;
            long oldSeg = segmentLen * (segmentLen + 1) / 2;

            long leftNewLen = pos - L;
            long rightNewLen = R - pos;
            long newSeg = (leftNewLen * (leftNewLen + 1)) / 2 + (rightNewLen * (rightNewLen + 1)) / 2;

            long reduction = oldSeg - newSeg;
            invalid -= reduction;

            marked.add(pos);

            long valid = totalSub - invalid;
            if (valid >= k) {
                return t;
            }
        }

        return -1;
    }
}
