public static long solve(String s, long[] order, long k) {
    int n = s.length();
    long totalSubstrings = (long) n * (n + 1) / 2;
    if (totalSubstrings < k) {
        return -1;
    }
    int[] timeReplaced = new int[n];
    for (int t = 0; t < n; t++) {
        int pos = (int) order[t];
        timeReplaced[pos] = t;
    }

    int low = 0;
    int high = n - 1;
    int ans = n - 1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        long validCount = computeValidCount(timeReplaced, mid, n, totalSubstrings);
        if (validCount >= k) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

private static long computeValidCount(int[] timeReplaced, int t0, int n, long totalSubstrings) {
    long invalid = 0;
    int current = 0;
    for (int i = 0; i < n; i++) {
        if (timeReplaced[i] > t0) {
            current++;
        } else {
            if (current > 0) {
                invalid += (long) current * (current + 1) / 2;
                current = 0;
            }
        }
    }
    if (current > 0) {
        invalid += (long) current * (current + 1) / 2;
    }
    return totalSubstrings - invalid;
}
```

